40	            // 削除インタラクションはサービスに委譲する
41	            // Delegate the delete interaction to the service
42	            _deleteObjectService.Update();
43	
44	            _screenClickableCameraController.GetNextUpdate();
45	            return null;
46	
47	            #region Internal
48	
