50	            {
51	                // OpenMenu(ポーズ)もESCにbindされ、ここで拾うとESCの選択キャンセル/モード終了が死ぬため破壊モードでは扱わない
52	                // OpenMenu(pause) is also bound to ESC; handling it here would shadow ESC's cancel/exit, so skip it in destroy mode
53	                if (InputManager.UI.BlockDelete.GetKeyDown) return new UITransitContext(UIStateEnum.GameScreen);
54	                if (UnityEngine.Input.GetKeyDown(KeyCode.B)) return new UITransitContext(UIStateEnum.BuildMenu);
55	                if (InputManager.UI.OpenInventory.GetKeyDown) return new UITransitContext(UIStateEnum.PlayerInventory);
56	
57	                // ESCはまず削除選択のキャンセルに使い、キャンセルする選択が無ければ破壊モードを抜ける
58	                // ESC is used first to cancel the delete selection; with nothing to cancel it leaves destroy mode
59	                if (InputManager.UI.CloseUI.GetKeyDown && !_deleteObjectService.TryCancelSelection())
60	                {
61	                    return new UITransitContext(UIStateEnum.GameScreen);
62	                }
63	                return null;
64	            }
65	
66	            #endregion
67	        }
68	
69	        public void OnExit()
70	        {
71	            _deleteObjectService.CancelSelection();
72	            _deleteBarObject.gameObject.SetActive(false);
73	
74	            _screenClickableCameraController.OnExit();
75	        }
76	    }
