1	using Cinemachine;
2	using Client.Common;
3	using Client.Game.InGame.UI.UIState.Input;
4	using Client.Input;
5	using DG.Tweening;
6	using UnityEngine;
7	using VContainer.Unity;
8	
9	namespace Client.Game.InGame.Control
10	{
11	    public class InGameCameraController : MonoBehaviour, IGameCamera, IInitializable
12	    {
13	        public Vector3 Position => transform.position;
14	        public Vector3 CameraEulerAngle => transform.rotation.eulerAngles;
15	        public float CameraDistance => _cinemachineFraming.m_CameraDistance;
16	        
17	        public Camera Camera => mainCamera;
18	        [SerializeField] private Camera mainCamera;
19	        
20	        [SerializeField] private CinemachineVirtualCamera virtualCamera;
21	        [SerializeField] private Vector2 sensitivity = Vector2.one;
22	        [SerializeField] private float lerpSpeed = 5.0f; // Adjust this to change the lerp speed
23	        
24	        private CinemachineFramingTransposer _cinemachineFraming;
25	        private Quaternion _targetRotation; // The rotation to smoothly rotate towards
26	        
27	        private DG.Tweening.Sequence _currentSequence;
28	        
29	        private bool _isControllable;
30	        
31	        public void Initialize()
32	        {
33	            CameraManager.RegisterCamera(this);
34	        }
35	        
36	        private void Awake()
37	        {
38	            _cinemachineFraming = virtualCamera.GetCinemachineComponent<CinemachineFramingTransposer>();
39	            _targetRotation = transform.rotation; // Initialize target rotation to current rotation
40	        }
41	        
42	        private void Update()
43	        {
44	            var distance = _cinemachineFraming.m_CameraDistance;
45	            if (UnityEngine.Input.GetKey(KeyCode.F1)) distance -= Time.deltaTime * 3f; // TODO InputManagerに移動
46	            if (UnityEngine.Input.GetKey(KeyCode.F2)) distance += Time.deltaTime * 3f; // TODO InputManagerに移動
47	            _cinemachineFraming.m_CameraDistance = Mathf.Clamp(distance, 0.6f, 10);
48	            
49	            if (!_isControllable && _currentSequence == null) return;
50	            
51	            //マウスのインプットによって向きを変える
52	            if (_isControllable)
53	            {
54	                GetMouseInput();
55	            }
56	            LeapCameraRotation();
57	            
58	            #region Internal
59	            
60	            void GetMouseInput()
61	            {
62	                var delta = InputManager.Player.Look.ReadValue<Vector2>();
63	                
64	                var rotation = _targetRotation.eulerAngles;
65	                rotation.x -= delta.y * sensitivity.y;
66	                if (90 < rotation.x && rotation.x < 180)
67	                    rotation.x = 90;
68	                else if (180 < rotation.x && rotation.x < 270) rotation.x = 270;
69	                
70	                rotation.y += delta.x * sensitivity.x;
71	                rotation.z = 0;
72	                _targetRotation = Quaternion.Euler(rotation);
73	            }
74	            
75	            void LeapCameraRotation()
76	            {
77	                var resultRotation = Quaternion.Lerp(transform.rotation, _targetRotation, lerpSpeed * Time.deltaTime);
78	                resultRotation = Quaternion.Euler(resultRotation.eulerAngles.x, resultRotation.eulerAngles.y, 0);
79	                transform.rotation = resultRotation;
80	            }
81	            
82	            #endregion
83	        }
84	        
85	        public void SetControllable(bool enable)
86	        {
87	            _isControllable = enable;
88	        }
89	        
90	        public void SetEnabled(bool cameraEnabled)
91	        {
92	            enabled = cameraEnabled;
93	            mainCamera.enabled = cameraEnabled;
94	            mainCamera.GetComponent<AudioListener>().enabled = cameraEnabled;
95	        }
96	        
97	        public void StartTweenCamera(Vector3 targetRotation, float targetDistance, float duration)
98	        {
99	            // DoTweenでカメラの向きを変える
100	            _currentSequence?.Kill();
101	            _currentSequence = DOTween.Sequence()
102	                .Append(DOTween.To(() => _targetRotation, x => _targetRotation = x, targetRotation, duration).SetEase(Ease.InOutQuad))
103	                .Join(DOTween.To(() => _cinemachineFraming.m_CameraDistance, x => _cinemachineFraming.m_CameraDistance = x, targetDistance, duration).SetEase(Ease.InOutQuad));
104	        }
105	        public void StartTweenCamera(TweenCameraInfo target)
106	        {
107	            StartTweenCamera(target.Rotation, target.Distance, target.TweenDuration);
108	        }
109	    }
110	}

