92	        public static Vector3Int CalcPlacePoint(BlockMasterElement holdingBlock, Vector3 hitPoint, int heightOffset, BlockDirection currentBlockDirection, PreviewSurfaceType? surfaceType)
93	        {
94	            var rotateAction = currentBlockDirection.GetCoordinateConvertAction();
95	            var rotatedSize = rotateAction(holdingBlock.BlockSize).Abs();
96	
97	            if (surfaceType == null)
98	            {
99	                var point = Vector3Int.zero;
100	                point.x = Mathf.FloorToInt(hitPoint.x + (rotatedSize.x % 2 == 0 ? 0.5f : 0));
101	                point.z = Mathf.FloorToInt(hitPoint.z + (rotatedSize.z % 2 == 0 ? 0.5f : 0));
102	                point.y = Mathf.FloorToInt(hitPoint.y);
103	
104	                point += new Vector3Int(0, heightOffset, 0);
105	                point -= new Vector3Int(rotatedSize.x, 0, rotatedSize.z) / 2;
106	
107	                return point;
108	            }
