110	            // 面に平行な軸（=面上のヒット位置）は偶数/奇数サイズで中央寄せスナップ
111	            // Axes parallel to the face snap with size-parity center alignment
112	            int SnapParallelX() => Mathf.FloorToInt(hitPoint.x + (rotatedSize.x % 2 == 0 ? 0.5f : 0)) - rotatedSize.x / 2;
113	            int SnapParallelY() => Mathf.FloorToInt(hitPoint.y + (rotatedSize.y % 2 == 0 ? 0.5f : 0)) - rotatedSize.y / 2;
114	            int SnapParallelZ() => Mathf.FloorToInt(hitPoint.z + (rotatedSize.z % 2 == 0 ? 0.5f : 0)) - rotatedSize.z / 2;
115	
116	            // 面に垂直な軸は面が整数グリッド上にあるためRoundToIntで浮動小数点誤差を吸収
117	            // Axis perpendicular to the face uses RoundToInt to absorb floating-point imprecision (face is on integer grid)
118	            var snapped = surfaceType.Value switch
