121	                // -Z face → new block origin = face - size
122	                PreviewSurfaceType.YX_Origin => new Vector3Int(SnapParallelX(), SnapParallelY(), Mathf.RoundToInt(hitPoint.z) - rotatedSize.z),
123	                // 既存ブロックの+Z面 → 新ブロックは+Z方向へ、原点は face
124	                // +Z face → new block origin = face
125	                PreviewSurfaceType.YX_Z => new Vector3Int(SnapParallelX(), SnapParallelY(), Mathf.RoundToInt(hitPoint.z)),
126	                PreviewSurfaceType.YZ_Origin => new Vector3Int(Mathf.RoundToInt(hitPoint.x) - rotatedSize.x, SnapParallelY(), SnapParallelZ()),
127	                PreviewSurfaceType.YZ_X => new Vector3Int(Mathf.RoundToInt(hitPoint.x), SnapParallelY(), SnapParallelZ()),
128	                PreviewSurfaceType.XZ_Origin => new Vector3Int(SnapParallelX(), Mathf.RoundToInt(hitPoint.y) - rotatedSize.y, SnapParallelZ()),
129	                PreviewSurfaceType.XZ_Y => new Vector3Int(SnapParallelX(), Mathf.RoundToInt(hitPoint.y), SnapParallelZ()),
130	                _ => throw new ArgumentOutOfRangeException(),
131	            };
132	
133	            // Q/Eの上下オフセットを面ヒット時にも一括で反映する
134	            // Apply Q/E vertical offset uniformly even when hitting an existing block face
135	            return snapped + new Vector3Int(0, heightOffset, 0);
