46	        {
47	            controller.Initialize();
48	            characterController = GetComponent<CharacterController>();
49	            SetPlayerPosition(initialHandshakeResponse.PlayerPos);
50	        }
51	        
52	        private void LateUpdate()
53	        {
54	            // 乗車中は補間済み車両poseを最後に反映する
55	            // Apply the interpolated train-car pose last while riding
56	            if (rideFollowTarget != null)
57	            {
58	                ApplyRideFollowPose();
59	                return;
60	            }
61	
62	            // 通常時だけ落下復帰処理を行う
63	            // Run fall recovery only during normal player control
64	            if (transform.localPosition.y < -50)
65	            {
66	                var point = SlopeBlockPlaceSystem.GetGroundPoint(transform.position);
67	                if (point.HasValue)
68	                {
69	                    SetPlayerPosition(new Vector3(transform.localPosition.x, point.Value.y, transform.localPosition.z));
70	                }
71	                else
72	                {
73	                    var spawnPoint = FindObjectsByType<SpawnPointObject>(FindObjectsInactive.Include, FindObjectsSortMode.None).FirstOrDefault();
74	                    if (spawnPoint == null)
75	                    {
76	                        SetPlayerPosition(new Vector3(0, 100, 0));
77	                        Debug.LogError("SpawnPointObject not found in the scene.");
78	                        return;
79	                    }
80	                    SetPlayerPosition(spawnPoint.transform.position);
81	                }
82	            }
83	        }
84	        
85	        /// <summary>
86	        ///     注意：アップデートのタイミングによってはThirdPersonController.csによる戻しが発生する可能性がある
